mapper.select:
SELECT * FROM customer_fail_reason_config
WHERE organization_id = #{orgId}
ORDER BY pos ASC

mapper.update:
UPDATE customer_fail_reason_config
SET name = #{config.name},
    pos = #{config.pos},
    update_time = #{config.updateTime},
    update_user = #{config.updateUser}
WHERE id = #{config.id} AND organization_id = #{config.organizationId}

